  ('social-worker-moex-06950', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '女性有沒有比男性更熱心從事志願服務？一位研究者以戶籍資料抽樣，調查18歲以上人口，發現女性每 週擔任志工的平均時數顯著高於男性。本研究的自變項與依變項為何？', '["自變項為每週擔任志工時數；依變項為性別", "自變項為女性；依變項為每週擔任志工時數", "自變項為性別是否有影響；依變項為每週擔任志工時數", "自變項為性別；依變項為每週擔任志工時數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
