  ('social-worker-moex-06954', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究新台灣之子的族群認同與其自我概念的關係，族群認同分成「父系認同」、「母系認同」、「雙族 群認同」三種，自我概念為量表分數，分數越高代表自我概念越正向。此研究最適合採用：', '["卡方檢定", "t檢定", "變異數分析", "迴歸分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06955', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述何者正確？', '["要知道兩個變項是不是線性關係，最簡單方式是求其迴歸線", "一般說來，我們可以使用同一個的迴歸方程式來以X預測Y或以Y預測X", "若兩變項間完全相關，則估計（以一個變項預測另一個變項）的標準誤為0", "如果迴歸線平行於X軸，則迴歸線的斜率等於1"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06956', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關眾數（mode）的敘述，何者正確﹖', '["它只適用於分析順序尺度的資料", "它適用於分析類別、順序、等距、等比尺度的資料", "它容易受到極端值（extreme value）影響", "它屬於離散趨勢量數的一種"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06957', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對於實驗與準實驗設計中，內、外在效度的敘述，何者正確﹖', '["某依變項觀察到的作用的確是由自變項而非由其他因素所造成的程度，稱為內部效度", "一項研究所描繪的因果關係在研究條件下可概化的程度，稱為內部效度", "某依變項觀察到的作用的確是由自變項而非由其他因素所造成的程度，稱為外部效度", "一項研究所描繪的因果關係在研究條件下不可概化的程度，稱為外部效度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06958', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請選出紮根理論（grounded theory）方法所包含四個階段的正確順序組合：①萃取理論精髓  ②整合不同', '["撰寫理論", "比較各事件在各類屬中的適合性", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
